import boto3
import json

class OptimizedAgentInvoker:
    def __init__(self, agent_id, use_guardrails=True):
        self.agent_id = agent_id
        self.use_guardrails = use_guardrails
        self.bedrock = boto3.client('bedrock-agent-runtime')

    def invoke_with_latency_optimization(self, session_id, input_text, session_state=None):
        # Skip guardrails for internal actions
        if 'actionGroup' in session_state or self.is_internal_exchange(session_state):
            alias_id = 'NO-GUARDRAILS-ALIAS'  # Pre-configured alias without guardrails
        else:
            alias_id = 'latest'

        response = self.bedrock.invoke_agent(
            agentId=self.agent_id,
            agentAliasId=alias_id,
            sessionId=session_id,
            inputText=input_text,
            sessionState=session_state,
            enableTrace=True
        )

        return {
            'completion': response['completion'],
            'trace': response['trace'],
            'guardrails_used': alias_id == 'latest',
            'latency_optimized': alias_id != 'latest'
        }

    def is_internal_exchange(self, session_state):
        return session_state and session_state.get('routingConfig', {}).get('agentToAgent')

