import vex
import boto3
import asyncio

# Vex monitors Bedrock Agent latency automatically
@vex.verify(issue_types=['llm-latency', 'cold-start', 'kb-retrieval'])
def optimized_bedrock_agent(agent_id: str, session_id: str, input_text: str) -> dict:
    bedrock = boto3.client('bedrock-agent-runtime')

    start_time = time.time()
    response = bedrock.invoke_agent(
        agentId=agent_id,
        agentAliasId='latest',
        sessionId=session_id,
        inputText=input_text,
        enableTrace=True
    )
    latency_ms = (time.time() - start_time) * 1000

    # Vex auto-detects latency issues
    trace = response['trace']
    vex.context.set({
        'agent_id': agent_id,
        'session_id': session_id,
        'total_latency_ms': latency_ms,
        'p95_threshold': 5000,
        'cold_start_detected': any('cold_start' in step for step in trace),
        'kb_latency': sum(step.get('retrievalLatency', 0) for step in trace if step.get('type') == 'knowledgeBase')
    })

    if latency_ms > 5000:
        vex.fail('AGENT_HIGH_LATENCY', f'Latency {latency_ms:.0f}ms exceeds P95 threshold')

    return {
        'completion': response['completion'],
        'trace': trace,
        'metrics': {'latency_ms': latency_ms}
    }

# Vex auto-remediates in production
@vex.auto_fix(issue_type='AGENT_HIGH_LATENCY')
def fix_bedrock_latency(context: dict) -> dict:
    # Auto-provision Lambda concurrency
    lambda_client = boto3.client('lambda')
    lambda_client.put_provisioned_concurrency_config(
        FunctionName=f'{context["agent_id"]}-action-group',
        Qualifier='$LATEST',
        ProvisionedConcurrencyConfiguration={'ProvisionedConcurrentExecutions': 10}
    )

    return {'status': 'remediated', 'action': 'provisioned_concurrency_applied'}
